.darma-loader-loading-io-17 {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 6px;
      height: 40px;
    }
    .darma-loader-loading-io-17 i {
      display: block;
      width: 6px;
      height: 40px;
      border-radius: 999px;
      background: linear-gradient(180deg, var(--loader-color, #f59e0b), var(--loader-secondary-color, #fde68a));
      transform-origin: center bottom;
      animation: darma-loader-loading-io-17-barPulse 0.91s ease-in-out infinite;
    }
    .darma-loader-loading-io-17 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loading-io-17 i:nth-child(2) { animation-delay: 0.09s; }
.darma-loader-loading-io-17 i:nth-child(3) { animation-delay: 0.18s; }
.darma-loader-loading-io-17 i:nth-child(4) { animation-delay: 0.27s; }
    @keyframes darma-loader-loading-io-17-barPulse { 0%, 100% { opacity: .25; transform: scaleY(.5); } 45% { opacity: 1; transform: scaleY(1); } }

